          <h1 className="text-4xl md:text-5xl font-serif font-bold mb-4">Our Professional Services</h1>
          <p className="text-xl text-gray-300 max-w-2xl mx-auto">
            We offer a comprehensive suite of audit, accounting, and advisory services designed to ensure your business is compliant, efficient, and prepared for growth.
          </p>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-12 space-y-12">
        {SERVICES.map((category, index) => (
          <div key={category.id} className="bg-white rounded-xl shadow-md overflow-hidden">
            <div className="md:flex">
              <div className="md:w-1/3 bg-slate-50 p-8 flex flex-col justify-center border-r border-gray-100">
                <category.icon size={56} className="text-lyno-green mb-6" />
                <h2 className="text-2xl font-serif font-bold text-lyno-blue mb-4">{category.title}</h2>
                <p className="text-gray-600 leading-relaxed text-sm">
                  {category.description}
                </p>
              </div>
              <div className="md:w-2/3 p-8 md:p-12">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {category.items.map((item, i) => (
                    <div key={i} className="flex items-start">
                      <div className="bg-emerald-100 rounded-full p-1 mr-3 mt-1 flex-shrink-0">
                        <Check size={14} className="text-lyno-green" />
                      </div>
                      <span className="text-slate-700 font-medium">{item}</span>
                    </div>
                  ))}
                </div>

                {/* Specific descriptions based on service type to add depth requested by prompt */}
                <div className="mt-8 pt-8 border-t border-gray-100 text-sm text-gray-500">
                  {category.id === 'assurance' && (
                    <p>
                      Our assurance services are designed to provide confidence to stakeholders. Whether you require a statutory audit for NBAA compliance or a specialized review of internal controls, our methodology focuses on risk identification and mitigation.
                    </p>
                  )}
                  {category.id === 'accounting' && (
                    <p>
                      We support businesses with poor or no records by establishing proper bookkeeping systems. From designing internal control systems to managing payroll and ensuring TRA tax compliance, we handle the numbers so you can focus on operations.
                    </p>
                  )}
                  {category.id === 'finance' && (
                    <p>
                       We act as your strategic financial partners. For clients without a dedicated CFO, we manage finances, improve process efficiency, and establish procedures that prevent revenue leakage and ensure capital is used effectively.
                    </p>
                  )}
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
