           />
           {/* Inner detail for depth */}
           <path 
             d="M12 6L13.5 10L18 10.5L14.5 13.5L15.5 18L12 16L8.5 18L9.5 13.5L6 10.5L10.5 10L12 6Z"
             fill={starColor}
             opacity="0.2"
