  );
};

export default App;

import React from 'react';

interface LogoProps {
  className?: string;
  variant?: 'light' | 'dark';
}

const Logo: React.FC<LogoProps> = ({ className = '', variant = 'dark' }) => {
  // Brand colors matched to the visual identity
  const starColor = '#06b6d4'; // Cyan-500

  // Adaptation for background contrast
  // variant='light' implies the logo is on a dark background (like the Navbar/Footer).
  // variant='dark' implies the logo is on a light background (like a white page section).
  const mainTextColor = variant === 'light' ? 'text-white' : 'text-[#2563eb]'; // White or Royal Blue
  const subTextColor = variant === 'light' ? 'text-gray-300' : 'text-[#1e3a8a]'; // Light Gray or Dark Blue

  return (
    <div className={`flex items-center gap-3 ${className}`}>
      {/* Star Icon - Interlaced Pentagram style */}
      <div className="relative w-12 h-12 flex-shrink-0">
         <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className="w-full h-full drop-shadow-sm">
           <path 
             d="M12 2 L18.5 21 L2.5 9.5 H21.5 L5.5 21 L12 2Z" 
             stroke={starColor} 
             strokeWidth="2" 
             strokeLinejoin="round" 
             strokeLinecap="round"
           />
        </svg>
      </div>

      <div className="flex flex-col justify-center select-none">
        {/* 2N Text - Heavy weight, tight tracking */}
        <span className={`text-4xl font-sans font-black tracking-tighter leading-none ${mainTextColor}`} style={{ fontFamily: 'Inter, sans-serif' }}>
          2N
        </span>
        {/* Company Name - Uppercase, wide tracking */}
        <span className={`text-[10px] font-sans font-bold uppercase tracking-[0.2em] leading-none mt-1 ${subTextColor}`}>
          Lyno Associate
        </span>
      </div>
    </div>
  );
};

export default Logo;

